previewCss:
.darma-loader-darma-custom-524 {color: var(--loader-color, #dc2626);
  --loader-secondary-color: #f97316;
  --loader-bg: #ffffff;
   height: 40px;
   aspect-ratio: 1.5;
   display: grid;
}
.darma-loader-darma-custom-524:before, .darma-loader-darma-custom-524:after  {
  content: "";
   background: currentColor;
   border-radius: 80px 80px 0 0;
   animation: darma-loader-darma-custom-524-l10 1s infinite alternate both;
}
.darma-loader-darma-custom-524:after  {
  transform: scale(-1);
   animation-delay: 0.2s;
}
@keyframes darma-loader-darma-custom-524-l10  {
  0%, 10% {margin-inline:0 33%}
50% {margin-inline:0 0}
90%, 100%{margin-inline:33% 0}
}

